    def prior_sampler(n: int) -> torch.Tensor:
        return torch.randn(n, 2)

    # Define toy simulator: x = theta + noise
    def simulator(theta: torch.Tensor) -> torch.Tensor:
        noise = 0.1 * torch.randn_like(theta)
        return theta + noise

    # Define latent sampler: z ~ N(0, I)
    def latent_sampler(n: int) -> torch.Tensor:
        return torch.randn(n, 2)

    # Simple generator: maps (x, z) to theta_fake
